changeSet.sql:
SET NOCOUNT ON;

CREATE TABLE #inv (rn INT IDENTITY(1,1) PRIMARY KEY, username VARCHAR(100) NOT NULL);

INSERT INTO #inv (username)
SELECT u.ID_
FROM   ACT_ID_USER u
JOIN   ACT_ID_MEMBERSHIP m ON m.USER_ID_ = u.ID_
WHERE  m.GROUP_ID_ = 'Invitors'
ORDER  BY NEWID();

DECLARE @inv_sup VARCHAR(100);
SELECT TOP 1 @inv_sup = username FROM #inv ORDER BY rn;

-- Clear any partial data from a previous failed run
DELETE FROM poc_supervisor_assignment;

INSERT INTO poc_supervisor_assignment (inviter_username, supervisor_username)
SELECT TOP 10 username, @inv_sup
FROM   #inv
WHERE  username <> @inv_sup
ORDER  BY rn;

DROP TABLE #inv;

SET NOCOUNT ON;

CREATE TABLE #sec (rn INT IDENTITY(1,1) PRIMARY KEY, username VARCHAR(100) NOT NULL);

INSERT INTO #sec (username)
SELECT u.ID_
FROM   ACT_ID_USER u
JOIN   ACT_ID_MEMBERSHIP m ON m.USER_ID_ = u.ID_
WHERE  m.GROUP_ID_ = 'Security'
ORDER  BY NEWID();

DECLARE @sec_sup VARCHAR(100);
SELECT TOP 1 @sec_sup = username FROM #sec ORDER BY rn;

DELETE FROM poc_security_supervisor_assignment;

INSERT INTO poc_security_supervisor_assignment (officer_username, supervisor_username)
SELECT TOP 10 username, @sec_sup
FROM   #sec
WHERE  username <> @sec_sup
ORDER  BY rn;

DROP TABLE #sec;

SET NOCOUNT ON;

CREATE TABLE #gk (rn INT IDENTITY(1,1) PRIMARY KEY, username VARCHAR(100) NOT NULL);

INSERT INTO #gk (username)
SELECT u.ID_
FROM   ACT_ID_USER u
JOIN   ACT_ID_MEMBERSHIP m ON m.USER_ID_ = u.ID_
WHERE  m.GROUP_ID_ = 'Porters'
ORDER  BY NEWID();

DECLARE @gk_sup VARCHAR(100);
SELECT TOP 1 @gk_sup = username FROM #gk ORDER BY rn;

DELETE FROM poc_gatekeeper_supervisor_assignment;

INSERT INTO poc_gatekeeper_supervisor_assignment (porter_username, supervisor_username)
SELECT TOP 10 username, @gk_sup
FROM   #gk
WHERE  username <> @gk_sup
ORDER  BY rn;

DROP TABLE #gk;
